    17→bool StringSanMatcher::match(const GENERAL_NAME* general_name) const {
    18→  if (general_name->type != general_name_type_) {
    19→    return false;
    20→  }
    21→  if (general_name->type == GEN_OTHERNAME) {
    22→    if (OBJ_cmp(general_name->d.otherName->type_id, general_name_oid_.get())) {
    23→      return false;
    24→    }
    25→  }
    26→  // For DNS SAN, if the StringMatcher type is exact, we have to follow DNS matching semantics.
    27→  const std::string san = Utility::generalNameAsString(general_name);
    28→  return general_name->type == GEN_DNS &&
    29→                 matcher_.matcher().match_pattern_case() ==
    30→                     envoy::type::matcher::v3::StringMatcher::MatchPatternCase::kExact
    31→             ? Utility::dnsNameMatch(matcher_.matcher().exact(), absl::string_view(san))
    32→             : matcher_.match(san);
    33→}
    34→
    35→SanMatcherPtr createStringSanMatcher(
    36→    envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher const& matcher,
    37→    Server::Configuration::CommonFactoryContext& context) {
    38→  // Verify that a new san type has not been added.
    39→  static_assert(envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::SanType_MAX ==
    40→                5);
    41→
    42→  switch (matcher.san_type()) {
    43→    PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
    44→  case envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::DNS:
    45→    return SanMatcherPtr{std::make_unique<StringSanMatcher>(GEN_DNS, matcher.matcher(), context)};
    46→  case envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::EMAIL:
    47→    return SanMatcherPtr{std::make_unique<StringSanMatcher>(GEN_EMAIL, matcher.matcher(), context)};
    48→  case envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::URI:
    49→    return SanMatcherPtr{std::make_unique<StringSanMatcher>(GEN_URI, matcher.matcher(), context)};
    50→  case envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::IP_ADDRESS:
    51→    return SanMatcherPtr{std::make_unique<StringSanMatcher>(GEN_IPADD, matcher.matcher(), context)};
    52→  case envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::OTHER_NAME: {
    53→    // Invalid/Empty OID returns a nullptr from OBJ_txt2obj
    54→    bssl::UniquePtr<ASN1_OBJECT> oid(OBJ_txt2obj(matcher.oid().c_str(), 0));
    55→    if (oid == nullptr) {
    56→      return nullptr;
    57→    }
    58→    return SanMatcherPtr{std::make_unique<StringSanMatcher>(GEN_OTHERNAME, matcher.matcher(),
    59→                                                            context, std::move(oid))};
    60→  }
    61→  case envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher::SAN_TYPE_UNSPECIFIED:
    62→    PANIC("unhandled value");
    63→  }
    64→  return nullptr;
    65→}
