    17→int attemptParseTagForErrorMessage(CBS& cbs) {
    18→  unsigned tag = 0;
    19→  if (!CBS_get_any_asn1_element(&cbs, nullptr, &tag, nullptr)) {
    20→    return -1;
    21→  }
    22→  return tag;
