    25→absl::StatusOr<std::unique_ptr<OcspResponse>>
    26→readDerEncodedOcspResponse(const std::vector<uint8_t>& der) {
    27→  CBS cbs;
    28→  CBS_init(&cbs, der.data(), der.size());
    29→
    30→  auto resp = Asn1OcspUtility::parseOcspResponse(cbs);
    31→  if (CBS_len(&cbs) != 0) {
    32→    return absl::InvalidArgumentError("Data contained more than a single OCSP response");
    33→  }
    34→
    35→  return resp;
    36→}
    37→
    38→absl::Status skipResponderId(CBS& cbs) {
    39→  // ResponderID ::= CHOICE {
    40→  //    byName               [1] Name,
    41→  //    byKey                [2] KeyHash
    42→  // }
    43→  //
    44→  // KeyHash ::= OCTET STRING -- SHA-1 hash of responder's public key
    45→  //    (excluding the tag and length fields)
    46→
    47→  auto opt1 = Asn1Utility::getOptional(cbs, CBS_ASN1_CONSTRUCTED | CBS_ASN1_CONTEXT_SPECIFIC | 1);
    48→  RETURN_IF_STATUS_NOT_OK(opt1);
    49→  auto opt2 = Asn1Utility::getOptional(cbs, CBS_ASN1_CONSTRUCTED | CBS_ASN1_CONTEXT_SPECIFIC | 2);
    50→  RETURN_IF_STATUS_NOT_OK(opt2);
    51→
    52→  if (opt1.value() || opt2.value()) {
    53→    return absl::OkStatus();
    54→  }
    55→
    56→  return absl::InvalidArgumentError(
    57→      absl::StrCat("Unknown choice for Responder ID: ", attemptParseTagForErrorMessage(cbs)));
    58→}
    59→
    60→absl::Status skipCertStatus(CBS& cbs) {
    61→  // CertStatus ::= CHOICE {
    62→  //  good                [0] IMPLICIT NULL,
    63→  //  revoked             [1] IMPLICIT RevokedInfo,
    64→  //  unknown             [2] IMPLICIT UnknownInfo
    65→  // }
    66→  auto opt1 = Asn1Utility::getOptional(cbs, CBS_ASN1_CONTEXT_SPECIFIC | 0);
    67→  RETURN_IF_STATUS_NOT_OK(opt1);
    68→  auto opt2 = Asn1Utility::getOptional(cbs, CBS_ASN1_CONSTRUCTED | CBS_ASN1_CONTEXT_SPECIFIC | 1);
    69→  RETURN_IF_STATUS_NOT_OK(opt2);
    70→  auto opt3 = Asn1Utility::getOptional(cbs, CBS_ASN1_CONTEXT_SPECIFIC | 2);
    71→  RETURN_IF_STATUS_NOT_OK(opt3);
    72→
    73→  if (!(opt1.value() || opt2.value() || opt3.value())) {
    74→    return absl::InvalidArgumentError(
    75→        absl::StrCat("Unknown OcspCertStatus tag: ", attemptParseTagForErrorMessage(cbs)));
    76→  }
    77→  return absl::OkStatus();
    78→}
