    96→absl::Status validateResponse(std::unique_ptr<OcspResponse>& response) {
    97→  if (response->status_ != OcspResponseStatus::Successful) {
    98→    return absl::InvalidArgumentError("OCSP response was unsuccessful");
    99→  }
   100→
   101→  if (response->response_ == nullptr) {
   102→    return absl::InvalidArgumentError("OCSP response has no body");
   103→  }
   104→
   105→  // We only permit a 1:1 of certificate to response.
   106→  if (response->response_->getNumCerts() != 1) {
   107→    return absl::InvalidArgumentError("OCSP Response must be for one certificate only");
   108→  }
   109→  return absl::OkStatus();
   110→}
