   112→absl::StatusOr<std::unique_ptr<OcspResponseWrapperImpl>>
   113→OcspResponseWrapperImpl::create(std::vector<uint8_t> der_response, TimeSource& time_source) {
   114→  auto response_or_error = readDerEncodedOcspResponse(der_response);
   115→  RETURN_IF_NOT_OK(response_or_error.status());
   116→  RETURN_IF_NOT_OK(validateResponse(response_or_error.value()));
   117→  return std::unique_ptr<OcspResponseWrapperImpl>{
   118→      new OcspResponseWrapperImpl(der_response, time_source, std::move(response_or_error.value()))};
   119→}
