   121→OcspResponseWrapperImpl::OcspResponseWrapperImpl(std::vector<uint8_t> der_response,
   122→                                                 TimeSource& time_source,
   123→                                                 std::unique_ptr<OcspResponse>&& response)
   124→    : raw_bytes_(std::move(der_response)), response_(std::move(response)),
   125→      time_source_(time_source) {
   126→  auto& this_update = response_->response_->getThisUpdate();
   127→  if (time_source_.systemTime() < this_update) {
   128→    std::string time_format(GENERALIZED_TIME_FORMAT);
   129→    DateFormatter formatter(time_format);
   130→    ENVOY_LOG_MISC(warn, "OCSP Response thisUpdate field is set in the future: {}",
   131→                   formatter.fromTime(this_update));
   132→  }
   133→}
