   135→// We use just the serial number to uniquely identify a certificate.
   136→// Though different issuers could produce certificates with the same serial
   137→// number, this is check is to prevent operator error and a collision in this
   138→// case is unlikely.
   139→bool OcspResponseWrapperImpl::matchesCertificate(X509& cert) const {
   140→  std::string cert_serial_number = CertUtility::getSerialNumberFromCertificate(cert);
   141→  std::string resp_cert_serial_number = response_->response_->getCertSerialNumber();
   142→  return resp_cert_serial_number == cert_serial_number;
   143→}
